:root {
  --primary-color: #3498db;
  --secondary-color: #2ecc71;
  --background-color: #2f3436;
  --font-family: 'Space Mono', monospace;
  --border-radius: 16px;
  --box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

body {
  font-family: var(--font-family);
  background-color: var(--background-color);
  margin: 0;
  padding: 0;
  overflow-x: hidden;
}

#root {
  width: 100%;
  height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
}

button {
  background-color: var(--primary-color);
  color: #fff;
  border: none;
  padding: 10px 20px;
  font-size: 16px;
  cursor: pointer;
  border-radius: var(--border-radius);
  box-shadow: var(--box-shadow);
  transition: transform 0.2s ease;
}

button:hover {
  transform: scale(1.05);
  box-shadow: 0 0 20px rgba(0, 0, 0, 0.4);
}

button:active {
  transform: scale(0.96);
}

::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-thumb {
  background-color: var(--primary-color);
  border-radius: var(--border-radius);
}

::selection {
  background-color: var(--primary-color);
  color: #fff;
}

.particle-bg {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-image: linear-gradient(120deg, #fdfbfb 0%, #ebedee 100%);
  background-size: 200% 200%;
  animation: gradient 10s ease infinite;
}

@keyframes gradient {
  0% {
    background-position: 0% 50%;
  }
  50% {
    background-position: 100% 50%;
  }
  100% {
    background-position: 0% 50%;
  }
}

import React from 'react';
import ReactDOM from 'react-dom';
import Menu from './components/Menu';
import Game from './components/Game';
import PauseMenu from './components/PauseMenu';
import StartScreen from './components/StartScreen';

const App = () => {
  const [state, setState] = React.useState('MENU');

  switch (state) {
    case 'MENU':
      return <Menu setState={setState} />;
    case 'PLAYING':
      return <Game setState={setState} />;
    case 'PAUSED':
      return <PauseMenu setState={setState} />;
    case 'GAME_OVER':
      return <StartScreen setState={setState} gameOver={true} />;
    case 'WIN':
      return <StartScreen setState={setState} gameOver={false} />;
    default:
      return <div>Invalid state</div>;
  }
};

ReactDOM.render(<App />, document.getElementById('root'));

